"use strict";(self.webpackChunkhalt_website=self.webpackChunkhalt_website||[]).push([[55924],{48359:e=>{e.exports=JSON.parse('{"tag":{"label":"congenital","permalink":"/docs/tags/congenital","allTagsPath":"/docs/tags","count":2,"items":[{"id":"guinea-pigs/illnesses-and-conditions/fetal-arrhythmia","title":"Fetal Arrhythmia in Guinea Pigs: What It Is and What It Means","description":"Pregnancy in guinea pigs can be a delicate time, requiring close monitoring and appropriate veterinary care. One rare but important condition that can arise is fetal arrhythmia, an irregular heartbeat detected in a developing fetus. While unsettling to hear about, understanding this condition can help owners and rescues make informed decisions.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/fetal-arrhythmia"},{"id":"guinea-pigs/illnesses-and-conditions/clubbed-feet","title":"Understanding Clubbed Feet and Limb Deformities in Guinea Pigs","description":"Guinea pigs are known for their sweet personalities and unique charm\u2014but some arrive into rescue with visible physical challenges, including limb deformities commonly referred to as \\"clubbed feet.\\" Understanding this condition is key to providing these special-needs pigs with the quality of life they deserve.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/clubbed-feet"}],"unlisted":false}}')}}]);